import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { OpenSellModuleParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/OpenSellModuleParser';

export class OpenSellModuleEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, OpenSellModuleParser);
    }

    public getParser(): OpenSellModuleParser {
        return this.parser as OpenSellModuleParser;
    }
}